  "path": "checkers.py",
  "start_line": 1,
  "replacement": "# This is the source code for a Checkers (Draughts) game.

import numpy as np
from enum import Enum, unique
class Player(Enum):
    EMPTY = 0
    RED = 1
    BLACK = -1
class PieceType(Enum):
    MAN = 0
    KING = 1
class Board:
    def __init__(self):
        self.state = np.zeros((8, 8), dtype=int)
        self.init_board()

    def init_board(self):
        for i in range(3):
            for j in range(i % 2, 8, 2):
                self.state[i][j] = Player.RED.value
        for i in range(5, 8):
            for j in range((i + 1) % 2, 8, 2):
                self.state[i][j] = Player.BLACK.value

    def print_board(self):
        symbols = {0: '.', 1: 'R', -1: 'B', 2: 'r', -2: 'b'}
        for row in self.state:
            print(' '.join(symbols[cell] for cell in row))

    def move_piece(self, start, end):
        piece = self.state[start[0]][start[1]]
        self.state[start[0]][start[1]] = Player.EMPTY.value
        self.state[end[0]][end[1]] = piece
        if (end[0] == 0 and piece == Player.BLACK.value) or (end[0] == 7 and piece == Player.RED.value):
            self.state[end[0]][end[1]] *= 2

    def is_valid_move(self, start, end):
        row_diff = abs(end[0] - start[0])
        col_diff = abs(end[1] - start[1])
        if not (row_diff == 1 and col_diff in (1, 2)):
            return False
        piece = self.state[start[0]][start[1]]
        new_piece = self.state[end[0]][end[1]]
        if end[1] != start[1]:
            if row_diff != 2 or new_piece != Player.EMPTY.value:
                return False
            intermediate = ((start[0] + end[0]) // 2, (start[1] + end[1]) // 2)
            if self.state[intermediate[0]][intermediate[1]] * piece > 0:
                return False
        return True
class Game:
    def __init__(self):
        self.board = Board()
        self.current_player = Player.RED.value

    def print_game_state(self):
        self.board.print_board()

    def play_move(self, move_str):
        start = tuple(int(x) for x in move_str.split('-')[0].split(','))
        end = tuple(int(x) for x in move_str.split('-')[1].split(','))
        if not self.board.is_valid_move(start, end):
            print('Invalid move! Try again.')
            return False
        self.board.move_piece(start, end)
        self.current_player *= -1
        return True
def main():
    game = Game()
    while True:
        game.print_game_state()
        if game.current_player == Player.RED.value:
            move_str = input('Red player (r1,c1-r2,c2): ')
        else:
            move_str = input('Black player (r1,c1-r2,c2): ')
        if game.play_move(move_str):
            break

if __name__ == '__main__':
    main()"
}}

